 25→
 26→    const [title, setTitle] = useState(initialTitle || '')
 27→    const [wordCount, setWordCount] = useState(0);
 28→    const [editor] = useLexicalComposerContext();
 29→
 30→
 31→    const [uploadedImagePaths, setUploadedImagePaths] = useState([]);
 32→
 33→    const addUploadedImagePath = useCallback((imagePath) =>{
