 22→const EditJournal = ({onClose, journalData}) => {
 23→    const {session, user} = useAuth();
 24→    const queryClient = useQueryClient();
 25→
 26→    const theme = {
 27→        paragraph: 'editor-paragraph',
 28→        heading: {
 29→            h1: 'editor-heading-h1',
 30→            h2: 'editor-heading-h2',
 31→            h3: 'editor-heading-h3',
 32→        },
 33→        quote: 'editor-quote',
 34→        text: {
 35→            bold: 'editor-text-bold',
 36→            italic: 'editor-text-italic',
 37→            underline: 'editor-text-underline',
 38→        }
 39→    }
 40→
 41→    const [title, setTitle] = useState(journalData?.title);
 42→    const [editorState , setEditorState] = useState(journalData?.content);
 43→    const [isUpdatingJournal, setIsUpdatingJournal] = useState(false);
 44→    const addUploadedImagePath = useCallback(() => {}, []);
 45→
 46→    const handleClickCloseEditor = (e) => {
 47→        e.stopPropagation();
 48→        onClose();
 49→    }
 50→
 51→    const saveEditJournal = async(e, journalId, journalContent, title) => {
 52→        e.stopPropagation();
 53→        const formdata = new FormData();
 54→        if(journalId){
 55→            formdata.append('journalId', journalId)
 56→        }
 57→        if(journalContent){
 58→            formdata.append('content', journalContent)
 59→        }
 60→        if(title){
 61→            formdata.append('title', title);
 62→        }
 63→
 64→        try {
 65→            setIsUpdatingJournal(true)
 66→            const message = await updateJournal(session?.access_token, formdata);
 67→            if(message){
 68→                // console.log(message)
 69→            }
 70→
 71→            queryClient.invalidateQueries(['userJournals', user?.userData?.[0].id])
 72→
 73→            setIsUpdatingJournal(false)
 74→            setTitle(null)
 75→            setEditorState(null)
 76→            onClose();
 77→        } catch (error) {
 78→            console.error("Error updating journal:", error);
 79→        } finally {
 80→            setTitle(null)
 81→            setEditorState(null)
 82→            setIsUpdatingJournal(false)
 83→            onClose()
 84→        }
 85→    }
 86→
 87→    const onChange = useCallback((state) => {
 88→        const jsonb = JSON.stringify(state.toJSON());
 89→        setEditorState(jsonb);
 90→    }, [])
 91→
 92→    return(
 93→        <div className='editor-parent-container' onClick={handleClickCloseEditor}>
 94→            <motion.div
 95→                className='editor-container'
 96→                initial={{scale: 0, opacity: 0.8}}
 97→                animate={{scale: 1, opacity: 1}}
 98→                exit={{scale: 0.8, opacity: 0}}
 99→                transition={{type: 'spring', stiffness: 260, damping: 25}}
100→                onClick={(e) => e.stopPropagation()}
101→            >
102→                <div className='editor-close-bttn-container'>
103→                    <button
104→                        onClick={handleClickCloseEditor}
105→                        className='editor-close-bttn'
106→                        aria-label="Close editor"
107→                        title="Close"
108→                    >
109→                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
110→                    </button>
111→                </div>
112→
113→                <input
114→                    value={title || ''}
115→                    onChange={(e) => setTitle(e.target.value)}
116→                    className='content-title-input'
117→                    type="text"
118→                    placeholder='Title'
119→                />
120→
121→                <LexicalComposer initialConfig={{
122→                    namespace: 'editContent',
123→                    theme: theme,
124→                    editable: true,
125→                    editorState: typeof journalData?.content === 'string'
126→                    ? journalData.content : JSON.stringify(journalData?.content),
127→                    nodes: [HeadingNode, ImageNode, QuoteNode, MentionNode],
128→                    onError(error){
129→                        throw error
130→                    },
131→                }}>
132→                    <div className="toolbar-wrapper">
133→                        <ToolBar addUploadedImagePath={addUploadedImagePath}/>
134→                    </div>
135→
136→                    <div className="editor-loader-wrapper">
137→                        {isUpdatingJournal && (
138→                            <BarLoader loading={isUpdatingJournal} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
139→                        )}
140→                    </div>
141→
142→                    <div className="editor-shell">
143→                        <RichTextPlugin
144→                            contentEditable={
145→                                <ContentEditable
146→                                    className="editor-input"
147→                                    aria-placeholder="Edit your post..."
148→                                    placeholder={<div className="editor-placeholder">Edit your post...</div>}
149→                                />
150→                            }
151→                            ErrorBoundary={LexicalErrorBoundary}
152→                        />
153→
154→                        <ImagePlugin addUploadedImagePath={addUploadedImagePath}/>
155→                        <MentionPlugin/>
156→                        <HistoryPlugin/>
157→                        <OnChangePlugin onChange={onChange}/>
158→                    </div>
159→
160→                    <div className='editor-footer'>
161→                        <span></span>
162→                        <button
163→                            onClick={(e) => saveEditJournal(e, journalData?.id, editorState, title)}
164→                            className='editor-save-bttn'
165→                            disabled={isUpdatingJournal}
166→                        >
167→                            Save edit
168→                        </button>
169→                    </div>
170→                </LexicalComposer>
171→            </motion.div>
172→        </div>
173→    )
174→}
175→
176→export default EditJournal;
